        kind: "shared-via",
        via: "claude-code",
        requiresPrimary: true,
      },
      schemaLabel: "repo-local CLAUDE.md",
      path: {
        posix: ["{repo}", "CLAUDE.md"],
        windows: ["{repo}", "CLAUDE.md"],
      },
