            name: "my-agent",
            agents: ["claude-code"],
            path: "agent.txt",
            scope: "repo",
          },
          dir,
          dir,
          realRoot,
          ["claude-code"],
          "/home/test",
          "/repo/test",
        ),
        /must point to a Markdown source file/,
      );
    } finally {
      await rm(dir, { recursive: true });
