    try {
      await writeFile(
        path.join(dir, "agent.md"),
        "---\nname: test-agent\ndescription: test\n---\n# Agent",
      );
      const realRoot = await realpath(dir);
      const { actions, warnings } = await compile(
        {
          name: "my-agent",
          agents: ["claude-code"],
