      );
      assert.equal(action.confidence, "documented");
    } finally {
      await rm(dir, { recursive: true });
    }
  });

  it("emits a warning and no action for codex (unsupported)", async () => {
    const compile = await getAdapter();
    const dir = await makeTmpDir();
